```cpp
int fibonacci(int n, int a = 0, int b = 1) {
    if (n == 0) {
        return a;
    }
    return fibonacci(n - 1, b, a + b);
}

int main() {
    int n;
    cout << "Enter the nth Fibonacci number: ";
    cin >> n;
    cout << "The " << n << "th Fibonacci number is: " << fibonacci(n) << endl;
    return 0;
}
```

